 27→void ULFPShopWidget::RefreshShopUI()
 28→{
 29→	if (Text_Title)
 30→	{
 31→		Text_Title->SetText(CachedShopDefinition.DisplayName.IsEmpty() ? FText::FromString(TEXT("遗物商店")) : CachedShopDefinition.DisplayName);
 32→	}
 33→
 34→	if (Text_Gold && CachedGameInstance)
 35→	{
 36→		Text_Gold->SetText(FText::FromString(FString::Printf(TEXT("金币: %d"), CachedGameInstance->GetGold())));
 37→	}
 38→
 39→	RefreshRelicList();
 40→	RefreshDetailPanel();
 41→}
