169→FString ULFPShopWidget::BuildEffectDescription(const FLFPRelicDefinition& Definition) const
170→{
171→	TArray<FString> Parts;
172→	for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
173→	{
174→		switch (Effect.EffectType)
175→		{
176→		case ELFPRelicEffectType::RET_MaxHealthFlat:
177→			Parts.Add(FString::Printf(TEXT("最大生命 %+d"), Effect.Value));
178→			break;
179→		case ELFPRelicEffectType::RET_AttackFlat:
180→			Parts.Add(FString::Printf(TEXT("攻击力 %+d"), Effect.Value));
181→			break;
182→		case ELFPRelicEffectType::RET_DefenseFlat:
183→			Parts.Add(FString::Printf(TEXT("防御力 %+d"), Effect.Value));
184→			break;
185→		case ELFPRelicEffectType::RET_SpeedFlat:
186→			Parts.Add(FString::Printf(TEXT("速度 %+d"), Effect.Value));
187→			break;
188→		default:
189→			break;
190→		}
191→	}
192→
193→	return Parts.Num() > 0 ? FString::Join(Parts, TEXT("\n")) : TEXT("无效果");
194→}
