 21→void ULFPBattleResultWidget::Setup(const FLFPBattleResult& Result, ULFPUnitRegistryDataAsset* Registry)
 22→{
 23→	CachedResult = Result;
 24→	UnitRegistry = Registry;
 25→
 26→	// 设置胜负文本
 27→	if (Text_Result)
 28→	{
 29→		if (Result.bVictory)
 30→		{
 31→			Text_Result->SetText(FText::FromString(TEXT("胜利")));
 32→		}
 33→		else if (Result.bEscaped)
 34→		{
 35→			Text_Result->SetText(FText::FromString(TEXT("撤退")));
 36→		}
 37→		else
 38→		{
 39→			Text_Result->SetText(FText::FromString(TEXT("败北")));
 40→		}
 41→	}
 42→
 43→	// 胜利：显示奖励
 44→	if (Result.bVictory)
 45→	{
 46→		if (Text_Gold)
 47→		{
 48→			Text_Gold->SetText(FText::FromString(FString::Printf(TEXT("金币: +%d"), Result.GoldReward)));
 49→		}
 50→		if (Text_Food)
 51→		{
 52→			Text_Food->SetText(FText::FromString(FString::Printf(TEXT("食物: +%d"), Result.FoodReward)));
 53→		}
 54→
 55→		// 捕获单位列表
 56→		if (Box_CapturedUnits)
 57→		{
 58→			Box_CapturedUnits->ClearChildren();
 59→
 60→			if (Result.CapturedUnits.Num() == 0)
 61→			{
 62→				Box_CapturedUnits->SetVisibility(ESlateVisibility::Collapsed);
 63→			}
 64→			else
 65→			{
 66→				Box_CapturedUnits->SetVisibility(ESlateVisibility::Visible);
 67→
 68→				for (const FLFPUnitEntry& CapturedUnit : Result.CapturedUnits)
 69→				{
 70→					FLFPUnitRegistryEntry RegistryEntry;
 71→					if (!UnitRegistry || !UnitRegistry->FindEntry(CapturedUnit.TypeID, RegistryEntry))
 72→					{
 73→						continue;
 74→					}
 75→
 76→					// 外层竖排容器：图标在上，名字在下
 77→					UVerticalBox* ItemBox = NewObject<UVerticalBox>(this);
 78→
 79→					// 图标
 80→					UImage* IconImage = NewObject<UImage>(this);
 81→					if (RegistryEntry.Icon)
 82→					{
 83→						IconImage->SetBrushFromTexture(RegistryEntry.Icon);
 84→					}
 85→					IconImage->SetDesiredSizeOverride(FVector2D(48.0, 48.0));
 86→					UVerticalBoxSlot* IconSlot = ItemBox->AddChildToVerticalBox(IconImage);
 87→					IconSlot->SetHorizontalAlignment(HAlign_Center);
 88→
 89→					// 名称
 90→					UTextBlock* NameText = NewObject<UTextBlock>(this);
 91→					NameText->SetText(RegistryEntry.DisplayName);
 92→					FSlateFontInfo FontInfo = NameText->GetFont();
 93→					FontInfo.Size = 12;
 94→					NameText->SetFont(FontInfo);
 95→					UVerticalBoxSlot* TextSlot = ItemBox->AddChildToVerticalBox(NameText);
 96→					TextSlot->SetHorizontalAlignment(HAlign_Center);
 97→
 98→					// 添加到 WrapBox
 99→					UWrapBoxSlot* WrapSlot = Cast<UWrapBoxSlot>(Box_CapturedUnits->AddChild(ItemBox));
100→					if (WrapSlot)
101→					{
102→						WrapSlot->SetPadding(FMargin(8.0f, 4.0f));
103→					}
104→				}
105→			}
106→		}
107→	}
108→	else
109→	{
110→		// 失败/逃跑：隐藏奖励区域
111→		if (Text_Gold)
112→		{
113→			Text_Gold->SetVisibility(ESlateVisibility::Collapsed);
114→		}
115→		if (Text_Food)
116→		{
117→			Text_Food->SetVisibility(ESlateVisibility::Collapsed);
118→		}
119→		if (Box_CapturedUnits)
120→		{
121→			Box_CapturedUnits->SetVisibility(ESlateVisibility::Collapsed);
122→		}
123→	}
124→}
