624→// ============== 玩家状态 ==============
625→
626→void ALFPWorldMapManager::InitializePlayer(int32 StartNodeID)
627→{
628→	if (!PlayerState)
629→	{
630→		PlayerState = NewObject<ULFPWorldMapPlayerState>(this);
631→	}
632→
633→	PlayerState->Initialize(StartNodeID);
634→
635→	// 生成或移动玩家棋子到起始节点
636→	ALFPWorldMapNode* StartNode = GetNode(StartNodeID);
637→	FVector StartLocation = StartNode ? StartNode->GetActorLocation() + FVector(0, 0, 1) : FVector::ZeroVector;
638→
639→	if (!PlayerPawn && PawnActorClass)
640→	{
641→		FActorSpawnParameters SpawnParams;
642→		SpawnParams.Owner = this;
643→		PlayerPawn = GetWorld()->SpawnActor<ALFPWorldMapPawn>(
644→			PawnActorClass, StartLocation, FRotator::ZeroRotator, SpawnParams);
