113→    CurrentActionCount = BaseActionCount;
114→    CurrentPhysicalBlock = BasePhysicalBlock;
115→    CurrentSpellDefense = BaseSpellDefense;
116→    CurrentWeight = BaseWeight;
117→
118→    AttackPower = CurrentAttack;
119→    MaxHealth = CurrentMaxHealth;
120→    MaxMovePoints = CurrentMaxMovePoints;
121→    Speed = CurrentSpeed;
122→    Defense = CurrentPhysicalBlock;
123→
124→    if (bResetHealth)
125→    {
126→        CurrentHealth = CurrentMaxHealth;
127→    }
128→    else
129→    {
